<?php
require '/var/www/memories-map/backend/vendor/autoload.php';
chdir('/var/www/memories-map/backend');
$app = require '/var/www/memories-map/backend/bootstrap/app.php';
$kernel = $app->make(Illuminate\Contracts\Console\Kernel::class);
$kernel->bootstrap();

$user = App\Models\User::where('email', 'mike@hart365.co.uk')->first();
$token = $user->createToken('debug')->plainTextToken;

// Create a tiny test image
$jpegData = base64_decode('');
file_put_contents('/tmp/test_debug.jpg', $jpegData);

echo "Token: $token\n\n";
echo "Testing upload API with curl...\n\n";

$ch = curl_init();
curl_setopt($ch, CURLOPT_URL, 'http://nginx/api/maps/1/media');
curl_setopt($ch, CURLOPT_POST, true);
curl_setopt($ch, CURLOPT_HTTPHEADER, [
    "Authorization: Bearer $token",
    "Accept: application/json",
]);
curl_setopt($ch, CURLOPT_POSTFIELDS, [
    'files[0]' => new CURLFile('/tmp/test_debug.jpg', 'image/jpeg', 'test_debug.jpg')
]);
curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);

$response = curl_exec($ch);
$httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
curl_close($ch);

echo "HTTP Status: $httpCode\n";
echo "Response:\n";
echo json_encode(json_decode($response), JSON_PRETTY_PRINT) . "\n";
